export type TestDiffType = 'new_failure' | 'fixed' | 'new' | 'removed' | 'regressed' | 'improved' | 'unchanged';

export interface TestDiff {
  testName: string;
  testFile: string;
  testSignature: string;
  diffType: TestDiffType;
  baselineStatus: string | null;
  currentStatus: string | null;
  baselineDurationMs: number | null;
  currentDurationMs: number | null;
  durationDeltaMs: number | null;
  durationDeltaPercent: number | null;
}

export interface ExecutionSummary {
  id: string;
  branch: string;
  commitSha: string;
  status: string;
  totalTests: number;
  passedTests: number;
  failedTests: number;
  skippedTests: number;
  flakyTests: number;
  durationMs: number;
  passRate: number;
  startedAt: string;
}

export interface ExecutionComparison {
  baseline: ExecutionSummary;
  current: ExecutionSummary;
  summary: {
    passRateDelta: number;
    durationDeltaMs: number;
    durationDeltaPercent: number;
    newFailures: number;
    fixed: number;
    newTests: number;
    removedTests: number;
    totalChanged: number;
  };
  testDiffs: TestDiff[];
}

export async function compareExecutions( organizationId: string, baselineExecutionId: string, currentExecutionId: string ): Promise<ExecutionComparison> { // Get execution summaries const [baseline, current] = await Promise.all([ getExecutionSummary(organizationId, baselineExecutionId), getExecutionSummary(organizationId, currentExecutionId), ]);
if (!baseline || !current) { throw new Error('One or both executions not found'); }
// Get test-level diff const testDiffs = await sql<TestDiff[]>` WITH baseline_tests AS ( SELECT test_name, test_file, CONCAT(test_file, '::', test_name) as test_signature, status, duration_ms FROM test_results WHERE execution_id = ${baselineExecutionId} ), current_tests AS ( SELECT test_name, test_file, CONCAT(test_file, '::', test_name) as test_signature, status, duration_ms FROM test_results WHERE execution_id = ${currentExecutionId} ) SELECT COALESCE(c.test_name, b.test_name) as "testName", COALESCE(c.test_file, b.test_file) as "testFile", COALESCE(c.test_signature, b.test_signature) as "testSignature", b.status as "baselineStatus", c.status as "currentStatus", b.duration_ms as "baselineDurationMs", c.duration_ms as "currentDurationMs", (c.duration_ms - b.duration_ms) as "durationDeltaMs", CASE WHEN b.duration_ms > 0 THEN ROUND(((c.duration_ms - b.duration_ms)::float / b.duration_ms * 100))::integer ELSE NULL END as "durationDeltaPercent", CASE WHEN b.test_signature IS NULL THEN 'new' WHEN c.test_signature IS NULL THEN 'removed' WHEN b.status = 'passed' AND c.status = 'failed' THEN 'new_failure' WHEN b.status = 'failed' AND c.status = 'passed' THEN 'fixed' WHEN b.status = c.status AND b.duration_ms IS NOT NULL AND c.duration_ms IS NOT NULL AND c.duration_ms > b.duration_ms * 1.2 THEN 'regressed' WHEN b.status = c.status AND b.duration_ms IS NOT NULL AND c.duration_ms IS NOT NULL AND c.duration_ms < b.duration_ms * 0.8 THEN 'improved' ELSE 'unchanged' END as "diffType" FROM baseline_tests b FULL OUTER JOIN current_tests c ON b.test_signature = c.test_signature ORDER BY CASE WHEN c.test_signature IS NULL OR b.test_signature IS NULL THEN 0 WHEN b.status = 'passed' AND c.status = 'failed' THEN 1 WHEN b.status = 'failed' AND c.status = 'passed' THEN 2 WHEN c.duration_ms > b.duration_ms * 1.2 THEN 3 ELSE 4 END, "testName" `;
// Calculate summary stats const newFailures = testDiffs.filter(t => t.diffType === 'new_failure').length; const fixed = testDiffs.filter(t => t.diffType === 'fixed').length; const newTests = testDiffs.filter(t => t.diffType === 'new').length; const removedTests = testDiffs.filter(t => t.diffType === 'removed').length;
return { baseline: { id: baseline.id, branch: baseline.branch, commitSha: baseline.commit_sha, status: baseline.status, totalTests: baseline.total_tests, passedTests: baseline.passed_tests, failedTests: baseline.failed_tests, skippedTests: baseline.skipped_tests || 0, flakyTests: baseline.flaky_tests || 0, durationMs: baseline.duration_ms, passRate: baseline.total_tests > 0 ? Math.round((baseline.passed_tests / baseline.total_tests) * 100) : 0, startedAt: baseline.started_at, }, current: { id: current.id, branch: current.branch, commitSha: current.commit_sha, status: current.status, totalTests: current.total_tests, passedTests: current.passed_tests, failedTests: current.failed_tests, skippedTests: current.skipped_tests || 0, flakyTests: current.flaky_tests || 0, durationMs: current.duration_ms, passRate: current.total_tests > 0 ? Math.round((current.passed_tests / current.total_tests) * 100) : 0, startedAt: current.started_at, }, summary: { passRateDelta: current.total_tests > 0 && baseline.total_tests > 0 ? Math.round( ((current.passed_tests / current.total_tests) - (baseline.passed_tests / baseline.total_tests)) * 100 ) : 0, durationDeltaMs: current.duration_ms - baseline.duration_ms, durationDeltaPercent: baseline.duration_ms > 0 ? Math.round(((current.duration_ms - baseline.duration_ms) / baseline.duration_ms) * 100) : 0, newFailures, fixed, newTests, removedTests, totalChanged: newFailures + fixed + newTests + removedTests, }, testDiffs, }; }
export async function getRecentExecutions( organizationId: string, limit: number = 20 ): Promise<{ id: string; branch: string; commitSha: string; startedAt: string; status: string }[]> { return sql` SELECT id, branch, commit_sha as "commitSha", started_at as "startedAt", status FROM test_executions WHERE organization_id = ${organizationId} ORDER BY started_at DESC LIMIT ${limit} `; }

import { NextResponse } from "next/server";
import { getSessionContext } from "@/lib/session-context";
import { compareExecutions } from "@/lib/db";

export const dynamic = "force-dynamic";

export async function GET(request: Request) {
  try {
    const context = await getSessionContext();
    if (!context) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { searchParams } = new URL(request.url);
    const baseline = searchParams.get("baseline");
    const current = searchParams.get("current");

    if (!baseline || !current) {
      return NextResponse.json(
        { error: "Both baseline and current execution IDs are required" },
        { status: 400 }
      );
    }

    const comparison = await compareExecutions(
      context.organizationId,
      baseline,
      current
    );

    return NextResponse.json(comparison);
  } catch (error) {
    console.error("[API] Error comparing executions:", error);
    return NextResponse.json(
      { error: "Failed to compare executions" },
      { status: 500 }
    );
  }
}

"use client";

import { useState, useEffect } from "react";
import {
  GitCompare,
  ArrowRight,
  ArrowUp,
  ArrowDown,
  Minus,
  CheckCircle2,
  XCircle,
  Plus,
  Trash2,
  Clock,
  Filter,
} from "lucide-react";
import type { ExecutionComparison, TestDiff, TestDiffType } from "@/lib/types";

const DIFF_TYPE_CONFIG: Record<TestDiffType, { label: string; color: string; icon: React.ElementType }> = {
  new_failure: { label: "New Failures", color: "text-red-500 bg-red-500/10", icon: XCircle },
  fixed: { label: "Fixed", color: "text-green-500 bg-green-500/10", icon: CheckCircle2 },
  new: { label: "New Tests", color: "text-blue-500 bg-blue-500/10", icon: Plus },
  removed: { label: "Removed", color: "text-gray-500 bg-gray-500/10", icon: Trash2 },
  regressed: { label: "Slower", color: "text-orange-500 bg-orange-500/10", icon: Clock },
  improved: { label: "Faster", color: "text-cyan-500 bg-cyan-500/10", icon: ArrowDown },
  unchanged: { label: "Unchanged", color: "text-muted-foreground bg-muted/10", icon: Minus },
};

function DeltaIndicator({ value, suffix = "" }: { value: number; suffix?: string }) {
  if (value === 0) return <span className="text-muted-foreground">-</span>;

  const isPositive = value > 0;
  const Icon = isPositive ? ArrowUp : ArrowDown;
  const color = isPositive ? "text-red-500" : "text-green-500";

  return (
    <span className={`flex items-center gap-1 ${color}`}>
      <Icon className="w-3 h-3" />
      {Math.abs(value)}{suffix}
    </span>
  );
}

function SummaryCard({ baseline, current, summary }: Pick<ExecutionComparison, 'baseline' | 'current' | 'summary'>) {
  return (
    <div className="grid grid-cols-3 gap-4 p-4 bg-muted/20 rounded-lg">
      {/* Baseline */}
      <div className="text-center">
        <p className="text-xs text-muted-foreground mb-1">Baseline</p>
        <p className="font-mono text-sm truncate" title={baseline.commitSha}>
          {baseline.commitSha.slice(0, 7)}
        </p>
        <p className="text-2xl font-bold">{baseline.passRate}%</p>
        <p className="text-xs text-muted-foreground">
          {baseline.passedTests}/{baseline.totalTests} passed
        </p>
      </div>

      {/* Arrow */}
      <div className="flex items-center justify-center">
        <ArrowRight className="w-8 h-8 text-muted-foreground" />
      </div>

      {/* Current */}
      <div className="text-center">
        <p className="text-xs text-muted-foreground mb-1">Current</p>
        <p className="font-mono text-sm truncate" title={current.commitSha}>
          {current.commitSha.slice(0, 7)}
        </p>
        <p className="text-2xl font-bold">{current.passRate}%</p>
        <p className="text-xs text-muted-foreground">
          {current.passedTests}/{current.totalTests} passed
        </p>
      </div>
    </div>
  );
}

function DiffStats({ summary }: { summary: ExecutionComparison['summary'] }) {
  return (
    <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mt-4">
      <div className="flex items-center gap-2 p-3 bg-red-500/10 rounded-lg">
        <XCircle className="w-5 h-5 text-red-500" />
        <div>
          <p className="text-xl font-bold">{summary.newFailures}</p>
          <p className="text-xs text-muted-foreground">New Failures</p>
        </div>
      </div>
      <div className="flex items-center gap-2 p-3 bg-green-500/10 rounded-lg">
        <CheckCircle2 className="w-5 h-5 text-green-500" />
        <div>
          <p className="text-xl font-bold">{summary.fixed}</p>
          <p className="text-xs text-muted-foreground">Fixed</p>
        </div>
      </div>
      <div className="flex items-center gap-2 p-3 bg-blue-500/10 rounded-lg">
        <Plus className="w-5 h-5 text-blue-500" />
        <div>
          <p className="text-xl font-bold">{summary.newTests}</p>
          <p className="text-xs text-muted-foreground">New Tests</p>
        </div>
      </div>
      <div className="flex items-center gap-2 p-3 bg-muted/30 rounded-lg">
        <Clock className="w-5 h-5 text-muted-foreground" />
        <div>
          <p className="text-sm font-bold">
            <DeltaIndicator value={summary.durationDeltaPercent} suffix="%" />
          </p>
          <p className="text-xs text-muted-foreground">Duration</p>
        </div>
      </div>
    </div>
  );
}

function TestDiffRow({ diff }: { diff: TestDiff }) {
  const config = DIFF_TYPE_CONFIG[diff.diffType];
  const Icon = config.icon;

  return (
    <div className="flex items-center justify-between py-3 border-b border-border/50 last:border-0">
      <div className="flex items-center gap-3 flex-1 min-w-0">
        <div className={`p-1.5 rounded ${config.color}`}>
          <Icon className="w-4 h-4" />
        </div>
        <div className="min-w-0">
          <p className="text-sm font-medium truncate">{diff.testName}</p>
          <p className="text-xs text-muted-foreground truncate">{diff.testFile}</p>
        </div>
      </div>

      <div className="flex items-center gap-4 ml-4">
        {diff.baselineStatus && (
          <span className={`text-xs px-2 py-0.5 rounded ${
            diff.baselineStatus === 'passed' ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400'
          }`}>
            {diff.baselineStatus}
          </span>
        )}
        <ArrowRight className="w-4 h-4 text-muted-foreground" />
        {diff.currentStatus && (
          <span className={`text-xs px-2 py-0.5 rounded ${
            diff.currentStatus === 'passed' ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400'
          }`}>
            {diff.currentStatus}
          </span>
        )}
        {diff.durationDeltaPercent !== null && Math.abs(diff.durationDeltaPercent) > 10 && (
          <span className="text-xs">
            <DeltaIndicator value={diff.durationDeltaPercent} suffix="%" />
          </span>
        )}
      </div>
    </div>
  );
}

interface RunComparisonProps {
  baselineId?: string;
  currentId?: string;
}

export function RunComparison({ baselineId, currentId }: RunComparisonProps) {
  const [comparison, setComparison] = useState<ExecutionComparison | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [filter, setFilter] = useState<TestDiffType | 'all'>('all');

  useEffect(() => {
    if (!baselineId || !currentId) return;

    setLoading(true);
    setError(null);

    fetch(`/api/executions/compare?baseline=${baselineId}&current=${currentId}`)
      .then((res) => res.json())
      .then((data) => {
        if (data.error) throw new Error(data.error);
        setComparison(data);
      })
      .catch((err) => setError(err.message))
      .finally(() => setLoading(false));
  }, [baselineId, currentId]);

  if (!baselineId || !currentId) {
    return (
      <div className="glass-card glass-card-glow p-6">
        <div className="flex items-center gap-2 mb-4">
          <GitCompare className="w-5 h-5 text-[oklch(0.75_0.15_195)]" />
          <h3 className="font-semibold">Compare Runs</h3>
        </div>
        <p className="text-sm text-muted-foreground">
          Select two executions to compare their results.
        </p>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="glass-card glass-card-glow p-6">
        <div className="flex items-center gap-2 mb-4">
          <GitCompare className="w-5 h-5 text-[oklch(0.75_0.15_195)]" />
          <h3 className="font-semibold">Compare Runs</h3>
        </div>
        <div className="space-y-4">
          <div className="h-24 bg-muted/30 rounded-lg animate-pulse" />
          <div className="grid grid-cols-4 gap-3">
            {[1, 2, 3, 4].map((i) => (
              <div key={i} className="h-20 bg-muted/30 rounded-lg animate-pulse" />
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (error || !comparison) {
    return (
      <div className="glass-card glass-card-glow p-6">
        <div className="flex items-center gap-2 mb-4">
          <GitCompare className="w-5 h-5 text-[oklch(0.75_0.15_195)]" />
          <h3 className="font-semibold">Compare Runs</h3>
        </div>
        <p className="text-sm text-red-500">{error || "Failed to load comparison"}</p>
      </div>
    );
  }

  const filteredDiffs = filter === 'all'
    ? comparison.testDiffs.filter(d => d.diffType !== 'unchanged')
    : comparison.testDiffs.filter(d => d.diffType === filter);

  return (
    <div className="glass-card glass-card-glow p-6">
      <div className="flex items-center gap-2 mb-4">
        <GitCompare className="w-5 h-5 text-[oklch(0.75_0.15_195)]" />
        <h3 className="font-semibold">Run Comparison</h3>
      </div>

      <SummaryCard
        baseline={comparison.baseline}
        current={comparison.current}
        summary={comparison.summary}
      />

      <DiffStats summary={comparison.summary} />

      {/* Filter */}
      <div className="flex items-center gap-2 mt-6 mb-4">
        <Filter className="w-4 h-4 text-muted-foreground" />
        <div className="flex gap-2 flex-wrap">
          <button
            onClick={() => setFilter('all')}
            className={`px-3 py-1 text-xs rounded-full transition-colors ${
              filter === 'all' ? 'bg-primary text-primary-foreground' : 'bg-muted/30 hover:bg-muted/50'
            }`}
          >
            All Changes ({comparison.summary.totalChanged})
          </button>
          {Object.entries(DIFF_TYPE_CONFIG)
            .filter(([key]) => key !== 'unchanged')
            .map(([key, config]) => {
              const count = comparison.testDiffs.filter(d => d.diffType === key).length;
              if (count === 0) return null;
              return (
                <button
                  key={key}
                  onClick={() => setFilter(key as TestDiffType)}
                  className={`px-3 py-1 text-xs rounded-full transition-colors ${
                    filter === key ? 'bg-primary text-primary-foreground' : 'bg-muted/30 hover:bg-muted/50'
                  }`}
                >
                  {config.label} ({count})
                </button>
              );
            })}
        </div>
      </div>

      {/* Test Diffs */}
      <div className="max-h-96 overflow-y-auto">
        {filteredDiffs.length === 0 ? (
          <p className="text-sm text-muted-foreground text-center py-8">
            No changes found
          </p>
        ) : (
          filteredDiffs.map((diff) => (
            <TestDiffRow key={diff.testSignature} diff={diff} />
          ))
        )}
      </div>
    </div>
  );
}

import { Suspense } from "react";
import { RunComparison } from "@/components/dashboard/run-comparison";
import { ExecutionSelector } from "@/components/dashboard/execution-selector";

export default function ComparePage({
  searchParams,
}: {
  searchParams: { baseline?: string; current?: string };
}) {
  return (
    <div className="container mx-auto p-6 space-y-6">
      <h1 className="text-2xl font-bold">Compare Test Runs</h1>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <ExecutionSelector
          label="Baseline"
          paramName="baseline"
          currentValue={searchParams.baseline}
        />
        <ExecutionSelector
          label="Current"
          paramName="current"
          currentValue={searchParams.current}
        />
      </div>

      <Suspense fallback={<div className="h-96 bg-muted/30 rounded-lg animate-pulse" />}>
        <RunComparison
          baselineId={searchParams.baseline}
          currentId={searchParams.current}
        />
      </Suspense>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { ChevronDown, GitBranch } from "lucide-react";

interface Execution {
  id: string;
  branch: string;
  commitSha: string;
  startedAt: string;
  status: string;
}

interface ExecutionSelectorProps {
  label: string;
  paramName: string;
  currentValue?: string;
}

export function ExecutionSelector({ label, paramName, currentValue }: ExecutionSelectorProps) {
  const [executions, setExecutions] = useState<Execution[]>([]);
  const [loading, setLoading] = useState(true);
  const [isOpen, setIsOpen] = useState(false);
  const router = useRouter();
  const searchParams = useSearchParams();

  useEffect(() => {
    fetch("/api/executions?limit=20")
      .then((res) => res.json())
      .then((data) => setExecutions(data.executions || []))
      .finally(() => setLoading(false));
  }, []);

  const selected = executions.find((e) => e.id === currentValue);

  const handleSelect = (id: string) => {
    const params = new URLSearchParams(searchParams.toString());
    params.set(paramName, id);
    router.push(`?${params.toString()}`);
    setIsOpen(false);
  };

  const formatDate = (date: string) => {
    return new Date(date).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  return (
    <div className="relative">
      <label className="text-sm font-medium text-muted-foreground mb-2 block">
        {label}
      </label>
      <button
        onClick={() => setIsOpen(!isOpen)}
        disabled={loading}
        className="w-full flex items-center justify-between p-3 bg-muted/30 rounded-lg border border-border hover:bg-muted/50 transition-colors"
      >
        {selected ? (
          <div className="flex items-center gap-2 text-left">
            <GitBranch className="w-4 h-4 text-muted-foreground" />
            <div>
              <p className="text-sm font-medium">{selected.branch}</p>
              <p className="text-xs text-muted-foreground font-mono">
                {selected.commitSha.slice(0, 7)} - {formatDate(selected.startedAt)}
              </p>
            </div>
          </div>
        ) : (
          <span className="text-muted-foreground">
            {loading ? "Loading..." : "Select execution"}
          </span>
        )}
        <ChevronDown className={`w-4 h-4 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute z-50 w-full mt-1 bg-background border border-border rounded-lg shadow-lg max-h-64 overflow-y-auto">
          {executions.map((exec) => (
            <button
              key={exec.id}
              onClick={() => handleSelect(exec.id)}
              className={`w-full flex items-center gap-2 p-3 text-left hover:bg-muted/50 transition-colors ${
                exec.id === currentValue ? 'bg-muted/30' : ''
              }`}
            >
              <GitBranch className="w-4 h-4 text-muted-foreground" />
              <div>
                <p className="text-sm font-medium">{exec.branch}</p>
                <p className="text-xs text-muted-foreground font-mono">
                  {exec.commitSha.slice(0, 7)} - {formatDate(exec.startedAt)}
                </p>
              </div>
              <span className={`ml-auto text-xs px-2 py-0.5 rounded ${
                exec.status === 'success' ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400'
              }`}>
                {exec.status}
              </span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

output_format.usage_example:
Navigate to comparison page: ``` /dashboard/compare?baseline=exec-123&current=exec-456 ```
Or use the component directly: ```tsx import { RunComparison } from "@/components/dashboard/run-comparison";
```
